actions
      .map((action): CoreMemoryActionInput | null => {
        if (!action || typeof action !== 'object') {
          return null;
        }
        const input = action as {
          op?: unknown;
          category?: unknown;
          key?: unknown;
          value?: unknown;
        };
        const op = typeof input.op === 'string' ? input.op.toLowerCase().trim() : '';
        if (op !== 'add' && op !== 'update' && op !== 'upsert' && op !== 'delete') {
          return null;
        }
        const key = typeof input.key === 'string' ? input.key.trim() : '';
        if (!key) {
          return null;
        }
        return {
          op,
          category:
            typeof input.category === 'string'
              ? (input.category.trim() as CoreMemoryActionInput['category'])
              : undefined,
          key,
          value: typeof input.value === 'string' ? input.value.trim() : null,
        } satisfies CoreMemoryActionInput;
      })
      .filter

rawChunks
        .map((item) => {
          if (!item || typeof item !== 'object') {
            return null;
          }
          const chunk = item as {
            summary?: unknown;
            details?: unknown;
            keywords?: unknown;
            source_turns?: unknown;
            sourceTurns?: unknown;
          };
          const sourceTurns = Array.isArray(chunk.source_turns)
            ? chunk.source_turns.filter((value): value is number => typeof value === 'number')
            : Array.isArray(chunk.sourceTurns)
              ? chunk.sourceTurns.filter((value): value is number => typeof value === 'number')
              : [];
          return {
            summary: typeof chunk.summary === 'string' ? chunk.summary.trim() : '',
            details:
              typeof chunk.details === 'string'
                ? chunk.details.trim()
                : typeof chunk.summary === 'string'
                  ? chunk.summary.trim()
                  : '',
            keywords: Array.isArray(chunk.keywords)
              ? chunk.keywords.filter((value): value is string => typeof value === 'string')
              : [],
            sourceTurns,
          };
        })
        .filter

item.raw_session
        .map((turn): MemoryTranscriptTurn | null => {
          if (!turn || typeof turn !== 'object') {
            return null;
          }
          const normalized: MemoryTranscriptTurn = {
            role:
              typeof (turn as { role?: unknown }).role === 'string'
                ? (turn as { role: string }).role
                : 'unknown',
            content:
              typeof (turn as { content?: unknown }).content === 'string'
                ? (turn as { content: string }).content
                : '',
          };
          if (typeof (turn as { messageId?: unknown }).messageId === 'string') {
            normalized.messageId = (turn as { messageId: string }).messageId;
          }
          if (typeof (turn as { timestamp?: unknown }).timestamp === 'number') {
            normalized.timestamp = (turn as { timestamp: number }).timestamp;
          }
          return normalized;
        })
        .filter

