record.actions
          .map((action) => {
            if (!action || typeof action !== 'object') {
              return null;
            }
            const input = action as {
              type?: unknown;
              chunk_id?: unknown;
              chunkId?: unknown;
              session_id?: unknown;
              sessionId?: unknown;
            };
            const type = typeof input.type === 'string' ? input.type : '';
            if (type !== 'expand_chunk' && type !== 'expand_session' && type !== 'get_raw_session') {
              return null;
            }
            const normalized: NavigationAction = { type };
            const chunkId =
              typeof input.chunkId === 'string'
                ? input.chunkId
                : typeof input.chunk_id === 'string'
                  ? input.chunk_id
                  : undefined;
            const sessionId =
              typeof input.sessionId === 'string'
                ? input.sessionId
                : typeof input.session_id === 'string'
                  ? input.session_id
                  : undefined;
            if (chunkId) {
              normalized.chunkId = chunkId;
            }
            if (sessionId) {
              normalized.sessionId = sessionId;
            }
            return normalized;
          })
