          return null;
        }
        return {
          id: buildSearchId('core', entry.combinedKey),
          recordId: entry.combinedKey,
          kind: 'core',
          title: entry.combinedKey,
          summary: entry.value,
          contentPreview: summarizeText(entry.value, 220),
          category: entry.category,
          sourceFile: this.deps.getCoreFilePath(),
          score,
          createdAt: 0,
          updatedAt: 0,
        };
      })
